class Solution {
public:
    int minSwapsCouples(vector<int>& row) {
        int n = row.size() / 2;
        vector<int> couple(n);
        for (int i = 0; i < row.size(); i += 2) {
            couple[(row[i] - 1) / 2] = row[i];
        }
        int res = 0, i = 0;
        while (i < n) {
            if (couple[i] != couple[i + 1] - 1) {
                int j = lower_bound(couple.begin() + i + 1, couple.end(), couple[i] + 1) - couple.begin();
                swap(couple[i], couple[j]);
                res++;
            }
            i++;
        }
        return res;
    }
};
```
